import{_ as e,o as a,c as o,ag as s}from"./chunks/framework.BYYsWsaA.js";const p=JSON.parse('{"title":"Themes & Layouts","description":"","frontmatter":{},"headers":[],"relativePath":"slides/themes-and-layouts.md","filePath":"slides/themes-and-layouts.md"}'),i={name:"slides/themes-and-layouts.md"};function l(r,t,n,d,h,c){return a(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="themes-layouts" tabindex="-1">Themes &amp; Layouts <a class="header-anchor" href="#themes-layouts" aria-label="Permalink to &quot;Themes &amp; Layouts&quot;">​</a></h1><p>Themes and layouts let you set the visual style of a deck once and reuse it across every slide.</p><h2 id="what-is-a-theme" tabindex="-1">What is a Theme? <a class="header-anchor" href="#what-is-a-theme" aria-label="Permalink to &quot;What is a Theme?&quot;">​</a></h2><p>A <strong>theme</strong> bundles the colors, fonts, and background used across a deck. Switching themes reskins the whole deck in one click — your content (text, images, shapes) stays put, only the visual treatment changes.</p><p>Each theme defines:</p><ul><li>A <strong>color scheme</strong> with theme roles (background, text, accent, etc.). Shapes and text bound to a theme role automatically update when you switch themes.</li><li>A <strong>font scheme</strong> for headings and body text. Text inside placeholders picks up the theme&#39;s heading or body font automatically.</li><li>A <strong>background</strong> style applied to every slide.</li></ul><h2 id="built-in-themes" tabindex="-1">Built-in Themes <a class="header-anchor" href="#built-in-themes" aria-label="Permalink to &quot;Built-in Themes&quot;">​</a></h2><p>Wafflebase ships with <strong>23 built-in themes</strong> covering neutral, light, editorial, vibrant, and dark looks. Open the <strong>Theme</strong> panel from the right sidebar to see thumbnails and apply one with a click.</p><ul><li><strong>Simple Light</strong> <em>(default)</em> and <strong>Simple Dark</strong> — neutral baselines</li><li>Streamline, Swiss, Paradigm, Material, Shift, Momentum, Focus, Luxe, Modern Writer, Coral, Spearmint, Pop, Tropic, Marina, Geometric, Plum, Slate, Forest, Spotlight, Beach Day</li><li><strong>Wafflebase</strong> — the Wafflebase brand palette</li></ul><p>New decks start on <strong>Simple Light</strong>. You can switch themes at any time — the theme picker shows a live preview of the active deck under each one.</p><h2 id="layouts" tabindex="-1">Layouts <a class="header-anchor" href="#layouts" aria-label="Permalink to &quot;Layouts&quot;">​</a></h2><p>A <strong>layout</strong> is a pre-arranged template for a slide — for example, &quot;Title slide&quot; or &quot;Title and body&quot;. Each layout defines a set of <strong>placeholders</strong> that you fill in with your content.</p><p>The built-in layouts match Google Slides:</p><table tabindex="0"><thead><tr><th>Layout</th><th>Use it for</th></tr></thead><tbody><tr><td>Title slide</td><td>The opening slide of a deck — large title + subtitle</td></tr><tr><td>Section header</td><td>Section dividers between groups of slides</td></tr><tr><td>Title and body</td><td>A title with a single body region (text, bullets, or content)</td></tr><tr><td>Title and two columns</td><td>A title above two side-by-side content regions</td></tr><tr><td>Title only</td><td>A title with the rest of the slide left blank</td></tr><tr><td>One column text</td><td>A full-width body region for prose-heavy slides</td></tr><tr><td>Main point</td><td>A single large takeaway, centered</td></tr><tr><td>Section title and description</td><td>A section title plus a paragraph of description</td></tr><tr><td>Caption</td><td>A large image area with a caption below</td></tr><tr><td>Big number</td><td>A single large numeric stat as the focal point</td></tr><tr><td>Blank</td><td>Empty canvas, no placeholders</td></tr></tbody></table><h2 id="changing-a-slide-s-layout" tabindex="-1">Changing a Slide&#39;s Layout <a class="header-anchor" href="#changing-a-slide-s-layout" aria-label="Permalink to &quot;Changing a Slide&#39;s Layout&quot;">​</a></h2><p>Open the <strong>Layout</strong> split-button on the toolbar (or right-click a slide in the thumbnail strip → <strong>Apply layout</strong>) and pick a new layout. The slide&#39;s existing placeholders are matched to the new layout&#39;s slots when their types align, so the title stays a title and the body stays a body.</p><h2 id="placeholders" tabindex="-1">Placeholders <a class="header-anchor" href="#placeholders" aria-label="Permalink to &quot;Placeholders&quot;">​</a></h2><p>A <strong>placeholder</strong> is a typed content slot in a layout — a title, a body, an image area, a footer. Placeholders carry the layout&#39;s default formatting (font, size, alignment) so text added through them automatically matches the theme.</p><p>When you switch layouts, Wafflebase preserves placeholder identity where possible: a title placeholder remains a title even if the new layout positions it differently, so its content survives the change.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="./build-a-deck.html">Build a Deck</a> — End-to-end tutorial</li><li><a href="./keyboard-shortcuts.html">Keyboard Shortcuts</a> — Layout switching, slide ops, and more</li></ul>',21)])])}const m=e(i,[["render",l]]);export{p as __pageData,m as default};
